var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"저건...... 클리포트의 마왕......?","JPN":"あれは……クリフォトの魔王……？","ENG":"Is that... a Demon Lord of Qliphoth?","TWN":"那是……逆卡巴拉魔王？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"}}}},{"id":"L4_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"데이터베이스에서 본 적 있어...... 하지만 어째서 이런 곳에?","JPN":"データベースで見たことがある……しかし、なぜこんなところに？","ENG":"I've seen them in the database before... But what's it doing here?","TWN":"我在資料庫看過……但是，為什麼會在這裡？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"서두르세요! 방주를 기동해서 여길 벗어나야 합니다!","JPN":"急いでください！　箱舟を起動してここを離れて！","ENG":"Hurry! We must activate the Ark and get out of here at once!","TWN":"快點！我們必須啟動方舟，趕快離開這裡！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"알렉스! 대원들과 함께 함선을 지키고 있어라!","JPN":"アレックス！　隊員たちと共に艦船の守りにつけ！","ENG":"Alex! Keep the ship secure with the troops!","TWN":"雅蕾克絲！和隊員們一起保護艦船！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"뭐? 넌 어떻게 하려고?","JPN":"えっ？　リュドミラちゃんはどうするの？","ENG":"What? What are you going to do?","TWN":"什麼？那妳要做什麼？"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"가서 시간을 벌겠다. 방주가 기동하기 전까지 저 괴물을 막아야 해.","JPN":"外に出て時間を稼ぐ。箱舟が起動するまであの化け物を止めなければ。","ENG":"I'm going to go buy us time. We must hold that monster at bay until the Ark is operational.","TWN":"我去爭取時間，在方舟啟動前，必須要擋下那個怪物。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"멍청한 소리 하지 마! 상대는 클리포트의 마왕이라고!","JPN":"バカ言わないで！　相手はクリフォトの魔王なのよ！","ENG":"Don't be stupid! This is a Demon Lord of Qliphoth we're talking about here!","TWN":"別說傻話了！對手是逆卡巴拉魔王啊！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"이래 봬도 관리국 전대장이다. 상대가 마왕이라고 해도 발목 정도는 잡을 수 있어.","JPN":"こう見えても管理局の戦隊長だ。\\nたとえ相手が魔王だろうと、足止めくらいは務められる。","ENG":"And I am a division commander of the Administration. Surely I'm capable of slowing down the enemy, even if it's a Demon Lord.","TWN":"別看我這樣，我可是管理局的戰隊隊長，就算對手是魔王，我也能夠拖住他。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그리고 너희를 여기까지 데리고 온 이상, 책임은 져야지.","JPN":"それに君たちをここまで付き合わせた以上、責任は取らなければな。","ENG":"Besides, I must take responsibility for bringing you all here.","TWN":"而且，既然我把你們帶來了這裡，就一定要負起責任。"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"지칠 대로 지친 상태로 뭘 어쩌겠다는 거야! 가 봤자 개죽음이라고!","JPN":"そんなヘトヘトな状態で何をするっていうの！\\n行ったって犬死にするだけだわ！","ENG":"You're already exhausted! There's not much you can do out there! You'll only get yourself killed!","TWN":"妳明明已經筋疲力盡了！妳去只是白白送死而已！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"GSWORD_ADMIN_NULL_NULL","text":{"KOREA":"그만둬! 류드밀라!!","JPN":"やめなさい！　リュドミラちゃん！！","ENG":"Don't! Lyudmila!!","TWN":"別去！盧德米拉！！"},"stage":{"bg":"PROLOGUE_03","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"후훗. 병정 개미들이 마중을 나와 주는군.","JPN":"ふふっ。兵隊アリがぞろぞろと迎え​に来てくれたわ。","ENG":"Heh heh. Looks like the soldier ants have come out to greet us.","TWN":"呵呵，兵蟻來迎接我了呢。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"반갑구나, 힐데의 아이들아.","JPN":"会えたことを嬉しく思うぞ、ヒルデの子どもたちよ。","ENG":"Greetings, children of Hilde.","TWN":"真高興見到你們，希爾德的孩子們。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ASMODEUS_FALLEN_NS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"게다가 이런 곳에서 널 만나다니......","JPN":"それに、こんなところで其方に会えるとは……","ENG":"And to meet you in a place like this...","TWN":"而且，沒想到會在這裡遇到你……"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ASMODEUS_FALLEN_NS_NULL","text":{"KOREA":"오늘은 행운도 내게 고개를 조아리는군.","JPN":"今日は幸運までもが妾に首を垂れているようじゃ。","ENG":"It seems that even fortune is prostrating before me today.","TWN":"看來今天的我有幸運女神的眷顧呢。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_ADMIN_NULL_NULL","text":{"KOREA":"......세피라의 수호자들이 나타난 이상, <color=#ffd34c>그녀</color>도 강림했겠죠.","JPN":"……セフィラの守護者たちが現れた以上、\\n<color=#ffd34c>彼女</color>も降臨しているはずです。","ENG":"The appearance of the Guardians of Sephira very likely signifies <color=#ffd34c>her</color> advent as well.","TWN":"……既然塞菲拉守護者出現了，那麼<color=#ffd34c>她</color>應該也會降臨吧。"},"stage":{"bg":"COUNTERSIDE_RED_ADF","slots":{"L":null,"C":{"char_id":"NAYUBIN_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};